const bridgeAsyncTestTimeout = 30 * time.Second

var discoverCodexSessionTestMu sync.Mutex

type recordingExecutor struct {
	prompts  []string
	sessions []Session
	result   ExecutionResult
	err      error
}

func (e *recordingExecutor) Run(_ context.Context, session *Session, prompt string) (ExecutionResult, error) {
	e.prompts = append(e.prompts, prompt)
	if session != nil {
		e.sessions = append(e.sessions, *session)
	}
	return e.result, e.err
}

type bridgeCodexLauncher struct {
	result codexrunner.LaunchResult
	err    error
	req    codexrunner.LaunchRequest
}

func (l *bridgeCodexLauncher) Launch(_ context.Context, req codexrunner.LaunchRequest) (codexrunner.LaunchResult, error) {
	l.req = req
	return l.result, l.err
}

type streamingRecordingExecutor struct {
	events []codexrunner.StreamEvent
	result ExecutionResult
	err    error
}

func (e *streamingRecordingExecutor) Run(ctx context.Context, session *Session, prompt string) (ExecutionResult, error) {
	return e.RunWithEventHandler(ctx, session, prompt, nil)
}

func (e *streamingRecordingExecutor) RunWithEventHandler(_ context.Context, _ *Session, _ string, handler codexrunner.EventHandler) (ExecutionResult, error) {
	for _, event := range e.events {
		if handler != nil {
			handler(event)
		}
	}
	return e.result, e.err
}

type transcriptWritingStreamingExecutor struct {
	write  func() error
	events []codexrunner.StreamEvent
	result ExecutionResult
	err    error
}

func (e *transcriptWritingStreamingExecutor) Run(ctx context.Context, session *Session, prompt string) (ExecutionResult, error) {
	return e.RunWithEventHandler(ctx, session, prompt, nil)
}

func (e *transcriptWritingStreamingExecutor) RunWithEventHandler(_ context.Context, _ *Session, _ string, handler codexrunner.EventHandler) (ExecutionResult, error) {
	for _, event := range e.events {
		if handler != nil {
			handler(event)
		}
	}
	if e.write != nil {
		if err := e.write(); err != nil {
			return ExecutionResult{}, err
		}
	}
	return e.result, e.err
}

type blockingStreamingExecutor struct {
	started chan struct{}
	release chan struct{}
	result  ExecutionResult
}

func (e *blockingStreamingExecutor) Run(ctx context.Context, session *Session, prompt string) (ExecutionResult, error) {
	return e.RunWithEventHandler(ctx, session, prompt, nil)
}

func (e *blockingStreamingExecutor) RunWithEventHandler(ctx context.Context, _ *Session, _ string, _ codexrunner.EventHandler) (ExecutionResult, error) {
	close(e.started)
	select {
	case <-ctx.Done():
		return ExecutionResult{}, ctx.Err()
	case <-e.release:
		return e.result, nil
	}
}

type serialStreamingExecutor struct {
	started chan string
	release chan struct{}
	mu      sync.Mutex
	prompts []string
}

func (e *serialStreamingExecutor) Run(ctx context.Context, session *Session, prompt string) (ExecutionResult, error) {
	return e.RunWithEventHandler(ctx, session, prompt, nil)
}

func (e *serialStreamingExecutor) RunWithEventHandler(ctx context.Context, _ *Session, prompt string, _ codexrunner.EventHandler) (ExecutionResult, error) {
	visible := strings.TrimSpace(StripHelperPromptEchoes(prompt))
	e.mu.Lock()
	e.prompts = append(e.prompts, visible)
	count := len(e.prompts)
	e.mu.Unlock()
	e.started <- visible
	select {
	case <-ctx.Done():
		return ExecutionResult{}, ctx.Err()
	case <-e.release:
		return ExecutionResult{Text: fmt.Sprintf("done %d: %s", count, visible), CodexThreadID: "thread-1", CodexTurnID: fmt.Sprintf("turn-%d", count)}, nil
	}
}

func (e *serialStreamingExecutor) promptSnapshot() []string {
	e.mu.Lock()
	defer e.mu.Unlock()
	return append([]string(nil), e.prompts...)
}

type parallelSessionStart struct {
	SessionID    string
	Prompt       string
	ModelProfile modelprofile.Snapshot
}

type parallelBlockingExecutor struct {
	started chan parallelSessionStart
	release chan struct{}
	mu      sync.Mutex
	prompts map[string][]string
}

func (e *parallelBlockingExecutor) Run(ctx context.Context, session *Session, prompt string) (ExecutionResult, error) {
	return e.RunWithEventHandler(ctx, session, prompt, nil)
}

func (e *parallelBlockingExecutor) RunWithEventHandler(ctx context.Context, session *Session, prompt string, _ codexrunner.EventHandler) (ExecutionResult, error) {
	sessionID := ""
	if session != nil {
		sessionID = session.ID
	}
	visible := strings.TrimSpace(StripHelperPromptEchoes(prompt))
	e.mu.Lock()
	if e.prompts == nil {
		e.prompts = make(map[string][]string)
	}
	e.prompts[sessionID] = append(e.prompts[sessionID], visible)
	count := len(e.prompts[sessionID])
	e.mu.Unlock()
	var snapshot modelprofile.Snapshot
	if session != nil {
		snapshot = session.ModelProfile
	}
	e.started <- parallelSessionStart{SessionID: sessionID, Prompt: visible, ModelProfile: snapshot}
	select {
	case <-ctx.Done():
		return ExecutionResult{}, ctx.Err()
	case <-e.release:
		return ExecutionResult{Text: fmt.Sprintf("done %s %d: %s", sessionID, count, visible), CodexThreadID: "thread-" + sessionID, CodexTurnID: fmt.Sprintf("turn-%s-%d", sessionID, count)}, nil
	}
}

func (e *parallelBlockingExecutor) promptCount(sessionID string) int {
	e.mu.Lock()
	defer e.mu.Unlock()
	return len(e.prompts[sessionID])
}

type blockingExecutor struct {
	started chan struct{}
	release chan struct{}
	result  ExecutionResult
}

func (e *blockingExecutor) Run(ctx context.Context, _ *Session, _ string) (ExecutionResult, error) {
	close(e.started)
	select {
	case <-ctx.Done():
		return ExecutionResult{}, ctx.Err()
	case <-e.release:
		return e.result, nil
	}
}

type attachmentReadingExecutor struct {
	prompt string
	err    error
}

func (e *attachmentReadingExecutor) Run(_ context.Context, _ *Session, prompt string) (ExecutionResult, error) {
	e.prompt = prompt
	for _, field := range strings.Fields(prompt) {
		if strings.Contains(field, "attachment-001") || strings.Contains(field, "file-001") {
			_, e.err = os.ReadFile(strings.Trim(field, " \t\r\n-()"))
			break
		}
	}
	if e.err != nil {
		return ExecutionResult{}, e.err
	}
	return ExecutionResult{Text: "saw attachment", CodexThreadID: "thread-1", CodexTurnID: "turn-1"}, nil
}

type imageInputRecordingExecutor struct {
	input      ExecutionInput
	imageRead  []byte
	imageError error
}

func (e *imageInputRecordingExecutor) Run(ctx context.Context, session *Session, prompt string) (ExecutionResult, error) {
	return e.RunInput(ctx, session, ExecutionInput{Prompt: prompt})
}

func (e *imageInputRecordingExecutor) RunInput(_ context.Context, _ *Session, input ExecutionInput) (ExecutionResult, error) {
	e.input = input
	if len(input.ImagePaths) > 0 {
		e.imageRead, e.imageError = os.ReadFile(input.ImagePaths[0])
		if e.imageError != nil {
			return ExecutionResult{}, e.imageError
		}
	}
	return ExecutionResult{Text: "saw image input", CodexThreadID: "thread-1", CodexTurnID: "turn-1"}, nil
}

func TestBridgeSessionMessagePersistsTurnRunsAndSendsOutbox(t *testing.T) {
	graph, sent := newBridgeTestGraph(t)
	store := newBridgeTestStore(t)
	executor := &recordingExecutor{result: ExecutionResult{
		Text:          "plain status reached codex",
		CodexThreadID: "thread-1",
		CodexTurnID:   "turn-1",
	}}
	bridge := newBridgeTestBridge(graph, store, executor)

	err := bridge.handleSessionMessage(context.Background(), "chat-1", bridgeTestMessage("message-1"), "status")
	if err != nil {
		t.Fatalf("handleSessionMessage error: %v", err)
	}
	if got := executor.prompts; len(got) != 1 || !strings.HasPrefix(got[0], "User message:\nstatus\n\nTeams helper safety:") || !strings.Contains(got[0], ArtifactManifestFenceInfo) {
		t.Fatalf("executor prompts = %#v, want user-prefixed status plus artifact handoff instructions", got)
	}
	if got := len(*sent); got != 2 {
		t.Fatalf("sent message count = %d, want ack plus final", got)
	}
	if !strings.Contains((*sent)[0].Content, "Codex is working") || !strings.Contains((*sent)[1].Content, "plain status reached codex") {
		t.Fatalf("sent content did not include ack and executor output: %#v", *sent)
	}

	state, err := store.Load(context.Background())
	if err != nil {
		t.Fatalf("Load error: %v", err)
	}
	if got := len(state.InboundEvents); got != 1 {
		t.Fatalf("inbound count = %d, want 1", got)
	}
	if got := len(state.Turns); got != 1 {
		t.Fatalf("turn count = %d, want 1", got)
	}
	if got := len(state.OutboxMessages); got != 2 {
		t.Fatalf("outbox count = %d, want ack plus final", got)
	}
	var turn teamstore.Turn
	for _, item := range state.Turns {
		turn = item
	}
	if turn.Status != teamstore.TurnStatusCompleted {
		t.Fatalf("turn status = %q, want completed", turn.Status)
	}
	if turn.CodexThreadID != "thread-1" || turn.CodexTurnID != "turn-1" {
		t.Fatalf("turn codex ids = %q/%q, want thread-1/turn-1", turn.CodexThreadID, turn.CodexTurnID)
	}
	var outbox teamstore.OutboxMessage
	for _, item := range state.OutboxMessages {
		outbox = item
	}
	if outbox.Status != teamstore.OutboxStatusSent || outbox.TeamsMessageID == "" {
		t.Fatalf("outbox not marked sent: %#v", outbox)
	}
	if got := bridge.reg.SessionByChatID("chat-1").CodexThreadID; got != "thread-1" {
		t.Fatalf("registry CodexThreadID = %q, want thread-1", got)
	}
}

func TestBridgeTreatsFinalAnswerCanceledLaunchAsCompleted(t *testing.T) {
	graph, sent := newBridgeTestGraph(t)
	store := newBridgeTestStore(t)
	finalText := "final answer before canceled context"
	launcher := &bridgeCodexLauncher{
		result: codexrunner.LaunchResult{Stdout: []byte(strings.Join([]string{
			`{"type":"session_meta","payload":{"id":"thread-final"}}`,
			`{"type":"event_msg","payload":{"type":"agent_message","turn_id":"turn-final","phase":"final_answer","message":` + strconv.Quote(finalText) + `}}`,
			`{"type":"event_msg","payload":{"type":"task_complete","turn_id":"turn-final","last_agent_message":` + strconv.Quote(finalText) + `}}`,
		}, "\n"))},
		err: context.Canceled,
	}
	executor := RunnerExecutor{Runner: &codexrunner.ExecRunner{Launcher: launcher}}
	bridge := newBridgeTestBridge(graph, store, executor)

	if err := bridge.handleSessionMessage(context.Background(), "chat-1", bridgeTestMessage("message-final-canceled"), "finish despite cancel"); err != nil {
		t.Fatalf("handleSessionMessage error: %v", err)
	}
	joined := sentPlainJoined(*sent)
	if !strings.Contains(joined, finalText) {
		t.Fatalf("sent messages missing final text:\n%s", joined)
	}
	if strings.Contains(joined, "error: context canceled") {
		t.Fatalf("completed final should not be reported as context canceled:\n%s", joined)
	}
	state, err := store.Load(context.Background())
	if err != nil {
		t.Fatalf("Load error: %v", err)
	}
	var turn teamstore.Turn
	var finalOutbox teamstore.OutboxMessage
	for _, item := range state.Turns {
		turn = item
	}
	for _, item := range state.OutboxMessages {
		if item.Kind == "final" {
			finalOutbox = item
		}
		if item.Kind == "error" {
			t.Fatalf("unexpected error outbox: %#v", item)
		}
	}
	if turn.Status != teamstore.TurnStatusCompleted || turn.CodexThreadID != "thread-final" || turn.CodexTurnID != "turn-final" {
		t.Fatalf("turn = %#v, want completed thread/turn ids", turn)
	}
	if finalOutbox.ID == "" || finalOutbox.NotificationKind != "turn_completed" {
		t.Fatalf("final outbox = %#v, want turn_completed final", finalOutbox)
	}
	hashes := knownTranscriptOutboxHashes(state, turn.SessionID)
	if !shouldSkipKnownTranscriptOutboxRecord(TranscriptRecord{Kind: TranscriptKindAssistant}, finalText, hashes) {
		t.Fatal("delivered final should dedupe the later transcript final")
	}
}

func TestBridgeRecoversCompletedHistoryFinalAfterCanceledExecution(t *testing.T) {
	graph, sent := newBridgeTestGraph(t)
	store := newBridgeTestStore(t)
	bridge := newBridgeTestBridge(graph, store, &recordingExecutor{
		result: ExecutionResult{Text: "initial answer", CodexThreadID: "thread-history", CodexTurnID: "turn-initial"},
	})

	if err := bridge.handleSessionMessage(context.Background(), "chat-1", bridgeTestMessage("message-history-initial"), "initial"); err != nil {
		t.Fatalf("handleSessionMessage initial error: %v", err)
	}

	finalText := "history final after canceled execution"
	historyPath := filepath.Join(t.TempDir(), "rollout-2026-05-22T15-59-00-thread-history.jsonl")
	stamp := time.Now().UTC().Add(time.Second).Format(time.RFC3339Nano)
	lines := []string{
		`{"timestamp":` + strconv.Quote(stamp) + `,"type":"session_meta","payload":{"id":"thread-history"}}`,
		`{"timestamp":` + strconv.Quote(stamp) + `,"type":"event_msg","payload":{"type":"agent_message","turn_id":"turn-history","phase":"final_answer","message":` + strconv.Quote(finalText) + `}}`,
		`{"timestamp":` + strconv.Quote(stamp) + `,"type":"event_msg","payload":{"type":"task_complete","turn_id":"turn-history","last_agent_message":` + strconv.Quote(finalText) + `}}`,
	}
	if err := os.WriteFile(historyPath, []byte(strings.Join(lines, "\n")+"\n"), 0o644); err != nil {
		t.Fatalf("write history file: %v", err)
	}
	prevDiscover := discoverCodexProjectsForTeams
	discoverCodexProjectsForTeams = func(context.Context, string) ([]codexhistory.Project, error) {
		return []codexhistory.Project{{
			Path: "/workspace",
			Sessions: []codexhistory.Session{{
				SessionID:   "thread-history",
				ProjectPath: "/workspace",
				FilePath:    historyPath,
			}},
		}}, nil
	}
	t.Cleanup(func() { discoverCodexProjectsForTeams = prevDiscover })

	bridge.executor = &recordingExecutor{err: context.Canceled}
	if err := bridge.handleSessionMessage(context.Background(), "chat-1", bridgeTestMessage("message-history-canceled"), "finish from history"); err != nil {
		t.Fatalf("handleSessionMessage canceled error: %v", err)
	}

	joined := sentPlainJoined(*sent)
	if !strings.Contains(joined, finalText) {
		t.Fatalf("sent messages missing recovered final:\n%s", joined)
	}
	if strings.Contains(joined, "error: context canceled") || strings.Contains(joined, "Teams helper stopped") {
		t.Fatalf("completed history final should not produce cancellation notice:\n%s", joined)
	}
	state, err := store.Load(context.Background())
	if err != nil {
		t.Fatalf("Load error: %v", err)
	}
	var completed teamstore.Turn
	for _, turn := range state.Turns {
		if turn.CodexTurnID == "turn-history" {
			completed = turn
			break
		}
	}
	if completed.Status != teamstore.TurnStatusCompleted || completed.CodexThreadID != "thread-history" {
		t.Fatalf("recovered turn = %#v, want completed thread-history/turn-history", completed)
	}
	for _, msg := range state.OutboxMessages {
		if msg.TurnID == completed.ID && (msg.Kind == "error" || msg.Kind == "interrupted") {
			t.Fatalf("unexpected cancellation outbox for recovered turn: %#v", msg)
		}
	}
}

func TestBridgeDoesNotRecoverStaleHistoryFinalAfterCanceledExecution(t *testing.T) {
	graph, sent := newBridgeTestGraph(t)
	store := newBridgeTestStore(t)
	bridge := newBridgeTestBridge(graph, store, &recordingExecutor{
		result: ExecutionResult{Text: "initial answer", CodexThreadID: "thread-stale", CodexTurnID: "turn-initial"},
	})

	if err := bridge.handleSessionMessage(context.Background(), "chat-1", bridgeTestMessage("message-stale-initial"), "initial"); err != nil {
		t.Fatalf("handleSessionMessage initial error: %v", err)
	}

	oldFinalText := "old history final that should not be reused"
	historyPath := filepath.Join(t.TempDir(), "rollout-2026-05-22T15-00-00-thread-stale.jsonl")
	oldStamp := time.Now().UTC().Add(-10 * time.Minute).Format(time.RFC3339Nano)
	lines := []string{
		`{"timestamp":` + strconv.Quote(oldStamp) + `,"type":"session_meta","payload":{"id":"thread-stale"}}`,
		`{"timestamp":` + strconv.Quote(oldStamp) + `,"type":"event_msg","payload":{"type":"agent_message","turn_id":"turn-old","phase":"final_answer","message":` + strconv.Quote(oldFinalText) + `}}`,
		`{"timestamp":` + strconv.Quote(oldStamp) + `,"type":"event_msg","payload":{"type":"task_complete","turn_id":"turn-old","last_agent_message":` + strconv.Quote(oldFinalText) + `}}`,
	}
	if err := os.WriteFile(historyPath, []byte(strings.Join(lines, "\n")+"\n"), 0o644); err != nil {
		t.Fatalf("write history file: %v", err)
	}
	prevDiscover := discoverCodexProjectsForTeams
	discoverCodexProjectsForTeams = func(context.Context, string) ([]codexhistory.Project, error) {
		return []codexhistory.Project{{
			Path: "/workspace",
			Sessions: []codexhistory.Session{{
				SessionID:   "thread-stale",
				ProjectPath: "/workspace",
				FilePath:    historyPath,
			}},
		}}, nil
	}
	t.Cleanup(func() { discoverCodexProjectsForTeams = prevDiscover })

	bridge.executor = &recordingExecutor{err: context.Canceled}
	if err := bridge.handleSessionMessage(context.Background(), "chat-1", bridgeTestMessage("message-stale-canceled"), "finish from stale history"); err != nil {
		t.Fatalf("handleSessionMessage canceled error: %v", err)
	}

	joined := sentPlainJoined(*sent)
	if strings.Contains(joined, oldFinalText) {
		t.Fatalf("stale history final was incorrectly sent:\n%s", joined)
	}
	if !strings.Contains(joined, "before it could verify a final Codex result") {
		t.Fatalf("missing interruption notice after stale history was ignored:\n%s", joined)
	}
	state, err := store.Load(context.Background())
	if err != nil {
		t.Fatalf("Load error: %v", err)
	}
	var interrupted teamstore.Turn
	for _, turn := range state.Turns {
		if turn.SessionID == "s001" && turn.Status == teamstore.TurnStatusInterrupted {
			interrupted = turn
			break
		}
	}
	if interrupted.ID == "" {
		t.Fatalf("expected canceled turn to remain interrupted, got %#v", state.Turns)
	}
	if interrupted.CodexTurnID == "turn-old" {
		t.Fatalf("stale Codex turn was bound to interrupted turn: %#v", interrupted)
	}
}

